INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("お！\nあそこに困ってそうな人発見！", "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1, 1, 0, "春咲 ひより", 1, 0, 0, 0, 0, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1001, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("大切な人を\n守れるようになりたい…って", "みんなみたいに\nわたしも強くならなきゃ", 1, 1, 0, "草野 優衣", 1, 0, 0, 0, 0, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1002, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("キミに必要な集中力と感性が", "フェンシングを始めてみては？", 1, 1, 0, "士条 怜", 1, 0, 0, 0, 0, "少しは磨かれると思いますよ。", 1003, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("今日はなにして遊ぶ？", "ねぇ、にいちゃん！", 1, 1, 0, "穂高 みそぎ", 1, 0, 0, 0, 0, "みそぎはねぇ、\nかくれんぼやりたい！", 1004, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("ねぇ…", "風宮あかりです", 1, 1, 0, "風宮 あかり", 1, 0, 0, 0, 0, "私といっしょに…\nいかない？", 1006, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("プリンたべたいのー", "出雲宮子なのー", 1, 1, 0, "出雲 宮子", 1, 0, 0, 0, 0, "食べ物の恨みは怖いのー", 1007, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("キミもボクの美貌に\n吸い寄せられたんだね。", "ボクは虹村雪。", 1, 1, 0, "虹村 雪", 1, 0, 0, 0, 0, "いいよ。\n見られることは運命さ…", 1008, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", "フッ…聞いて後悔するがいい！", 1, 1, 0, "柊杏奈", 1, 0, 0, 0, 0, "人呼んで「疾風の冥姫」!!", 1009, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("うさぎさん、\n運命の王子はんに巡りあわせてくれて", "マホマホ王国のプリンセス、\nまほ姫どす", 1, 1, 0, "姫宮 真歩", 1, 0, 0, 0, 0, "ほんまおおきにやわ～♪", 1010, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("生き別れたお兄ちゃんを探して\n三千世界！", "衣之咲璃乃です！", 1, 1, 0, "衣之咲 璃乃", 1, 0, 0, 0, 0, "ここで会ったが\n100年目～！", 1011, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("ち、超能力って…\n何のことかな～？", "私はハツネ、\n結構強いんだよ。\nきらーん☆", 1, 1, 0, "柏崎 初音", 1, 0, 0, 0, 0, "…って、お願い！\n誰にも言わないでおいて～！", 1012, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("一応カリスマ読モJKやってまっす！", "ちょす！\n美波鈴奈だよ～♪", 1, 1, 0, "美波 鈴奈", 1, 0, 0, 0, 0, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1016, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("東京は遊園地みたいなところさー", "はいたーい。\n喜屋武香織さー。", 1, 1, 0, "喜屋武 香織", 1, 0, 0, 0, 0, "でも、沖縄もとってもいいとこさー", 1017, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("先生って呼ばれるのは\nくすぐったいから", "支倉伊緒です。", 1, 1, 0, "支倉 伊緒", 1, 0, 0, 0, 0, "イオちゃんって呼んでね。", 1018, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("あ！/\お兄ちゃ～ん\nまってよ～", "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1, 1, 0, "茜 ミミ", 1, 0, 0, 0, 0, "ミミをおいてかないでぇ～", 1020, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("あの……\nふぇ……", "あ…あの…えっと…\n栗…林…くるみ…です……", 1, 1, 0, "栗林 くるみ", 1, 0, 0, 0, 0, "ふぇぇぇぇぇん……", 1021, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("こんな私に貴重な時間を\n割いていただき、", "風宮よりです。\nあああああ！", 1, 1, 0, "風宮 より", 1, 0, 0, 0, 0, "なんてありがとうございます！", 1022, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("おにいちゃんどこいくの？\nえ？", "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1, 1, 0, "北条 綾音", 1, 0, 0, 0, 0, "私こっち行きたいー\nね、早く早くー", 1023, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("ふ、不束者ですが\nどうぞ末永く…って、", "わっ…わっ…私、\n天野すずめといいます！", 1, 1, 0, "天野 すずめ", 1, 0, 0, 0, 0, "これて何か違う…\nあああすみません！", 1025, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("あなたは…運命の……\n伴侶……", "……クスクス…私は\n…倉石恵理子……", 1, 1, 0, "倉石 恵理子", 1, 0, 0, 0, 0, "離しませんわ………\n絶対に…!!", 1027, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1, 1, 0, "佐々木 咲恋", 1, 0, 0, 0, 0, "…そうでしょ？？", 1028, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("ぇっと…\nキミ、私のこと知らないの?!", "桜井望だよ！\nよろしくねっ", 1, 1, 0, "桜井 望", 1, 0, 0, 0, 0, "あはは、\n私もまだまだだなぁ～", 1029, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("初めまして、\n私はニノン・ジュベール申すデス！", "デケデケデンっ！", 1, 1, 0, "ニノン・ジュベール", 1, 0, 0, 0, 0, "ショーグン、\nワタシと一緒に天下統一デース！", 1030, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("でもって私の隣にいるのが……\nえ、見えない？", "上喜しのぶです。\n手元のドクロが父です。", 1, 1, 0, "上喜 しのぶ", 1, 0, 0, 0, 0, "おかしいですね……", 1031, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("けんども\nそれには足りないモンが…", "目指すはビッグな\nお笑い芸人だっぺ！", 1, 1, 0, "野戸まひる", 1, 0, 0, 0, 0, "そう、\nオラのボケに突っ込める相方が…！", 1033, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("ちょっと緊張しちゃって…", "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1, 1, 0, "綾瀬 ゆかり", 1, 0, 0, 0, 0, "ちょ\nちょっと一杯飲んできます…！", 1034, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("知らない人とは話しちゃいけないので", "氷川鏡華…です", 1, 1, 0, "氷川 鏡華", 1, 0, 0, 0, 0, "これ以上お話しすることは…\nないです！", 1036, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("……あ、アラーム。", "柏崎…栞です。", 1, 1, 0, "柏崎 栞", 1, 0, 0, 0, 0, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1038, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("私、一人も友達がいなくて……", "ふ、双葉碧です。", 1, 1, 0, "双葉 碧", 1, 0, 0, 0, 0, "野に咲く花が、\n唯一の話相手です。", 1040, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("私の歌声で、\n皆さんが幸せになってくれたらいいなって…", "三角千歌です。", 1, 1, 0, "三角 千歌", 1, 0, 0, 0, 0, "そう思っています。", 1042, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("あぁ？\nお前のそいつの仲間か？", "安芸真琴だ。", 1, 1, 0, "安芸 真琴", 1, 0, 0, 0, 0, "う、疑ってすまなかったな…", 1043, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("生けとし生ける全ての者よ！", "わらわこそは夜を総べる者！", 1, 1, 0, "イリヤ・オーンスタイン", 1, 0, 0, 0, 0, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1044, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("ぐふふふふ……はっ！", "そこで騎士は妖精を乱暴に……", 1, 1, 0, "遠見 空花", 1, 0, 0, 0, 0, "ｌク、クウカに何かご用ですか!?", 1045, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("自由気ままで♪\n寝て遊んで、食べてケンカして…", "宮坂たまきにゃ♪\n猫はいいにゃよ？", 1, 1, 0, "宮坂たまき", 1, 0, 0, 0, 0, "う～ん…\n猫ってホントに最高にゃ～♪", 1046, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("それでは早速クエストに…", "大神美冬よ！", 1, 1, 0, "大神 美冬", 1, 0, 0, 0, 0, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1048, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("クエストもバトルも\n掃除も洗濯も", "星野静流だよ！", 1, 1, 0, "星野静流", 1, 0, 0, 0, 0, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1049, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("見ての通りの\nセクシー美少女で", "アタシは玉泉美咲。", 1, 1, 0, "玉泉美咲", 1, 0, 0, 0, 0, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1050, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("？？？？", "？？？", 1, 1, 0, "リマ", 1, 0, 0, 0, 0, "？？？？", 1052, 1.4, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("菓子でつろうなどと\n稚拙な策を……", "モニカ・ヴァイスヴィントだ。", 1, 1, 0, "モニカ・ヴァイスヴィント", 1, 0, 0, 0, 0, "そ、そこまでいうなら\nもらってやる", 1053, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("菓子でつろうなどと\n稚拙な策を……", "モニカ・ヴァイスヴィントだ。", 1, 1, 0, "ペコリーヌ", 1, 0, 0, 0, 0, "そ、そこまでいうなら\nもらってやる", 1058, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("菓子でつろうなどと\n稚拙な策を……", "モニカ・ヴァイスヴィントだ。", 1, 1, 0, "コッコロ", 1, 0, 0, 0, 0, "そ、そこまでいうなら\nもらってやる", 1059, 1.5, 2);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES ("菓子でつろうなどと\n稚拙な策を……", "モニカ・ヴァイスヴィントだ。", 1, 1, 0, "キャル", 1, 0, 0, 0, 0, "そ、そこまでいうなら\nもらってやる", 1060, 1.5, 2);
